import React from 'react';
// IMPORTANTE: Agregados Box, Users y Trash2 que faltaban
import { Box, Users, Trash2 } from 'lucide-react';

const ListaOfertas = ({ ofertas, onDelete }) => {
  if (ofertas.length === 0) return <div style={emptyStateStyle}><p>No hay ofertas.</p></div>;

  return (
    <div style={gridStyle}>
      {ofertas.map((o) => {
        const ahorro = Math.round(((o.precioViejo - o.precioNuevo) / o.precioViejo) * 100);
        return (
          <div key={o.id} style={cardStyle}>
            <div style={imageWrapper}>
              {/* Corregido: antes decía style={img} y ahora style={imgStyle} */}
              <img src={o.imagen} alt={o.producto} style={imgStyle} />
              <div style={ahorroBadge}>-{ahorro}%</div>
            </div>

            <div style={{ padding: '15px' }}>
              <h3 style={{ margin: '0 0 10px 0' }}>{o.producto}</h3>
              
              <div style={{ display: 'flex', alignItems: 'baseline', gap: '10px' }}>
                <span style={precioNuevoStyle}>${o.precioNuevo}</span>
                <span style={precioViejoStyle}>${o.precioViejo}</span>
              </div>

              <div style={divider} />

              <div style={statsContainer}>
                <div style={statItem}><Box size={14} /> <span>Stock: <strong>{o.stock}</strong></span></div>
                <div style={statItem}><Users size={14} /> <span>Máx: <strong>{o.limitePorCliente}</strong></span></div>
              </div>

              <button onClick={() => onDelete(o.id)} style={btnDelete}>
                <Trash2 size={14} /> Eliminar
              </button>
            </div>
          </div>
        );
      })}
    </div>
  );
};

// Estilos
const gridStyle = { display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(260px, 1fr))', gap: '20px' };
const cardStyle = { background: 'white', borderRadius: '18px', border: '1px solid #e2e8f0', overflow: 'hidden' };
const imageWrapper = { height: '150px', position: 'relative', background: '#f1f5f9' };
const imgStyle = { width: '100%', height: '100%', objectFit: 'cover' };
const ahorroBadge = { position: 'absolute', bottom: '10px', left: '10px', background: '#ef4444', color: 'white', padding: '4px 8px', borderRadius: '6px', fontSize: '0.8rem', fontWeight: 'bold' };
const precioNuevoStyle = { fontSize: '1.5rem', fontWeight: '800', color: '#1e293b' };
const precioViejoStyle = { fontSize: '1rem', textDecoration: 'line-through', color: '#94a3b8' };
const divider = { height: '1px', background: '#f1f5f9', margin: '12px 0' };
const statsContainer = { display: 'flex', justifyContent: 'space-between', marginBottom: '15px' };
const statItem = { display: 'flex', alignItems: 'center', gap: '5px', fontSize: '0.75rem', color: '#64748b' };
const btnDelete = { width: '100%', padding: '8px', background: '#fff1f2', color: '#e11d48', border: 'none', borderRadius: '8px', cursor: 'pointer', fontSize: '0.8rem', fontWeight: 'bold', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '5px' };
const emptyStateStyle = { textAlign: 'center', padding: '40px', color: '#94a3b8' };

export default ListaOfertas;
